INSERT INTO `v1_fb2df9394343aaaa378a30077f8a2452b7e4e67ba9024e68f0c7886197ee5c0a` VALUES (0, 0, "2025/12/31 11:59:59", "ミヤコ（クリスマス）", 119901, 2.17, "【物理】中衛で、味方をプリンで強化する幽霊聖少女。\n物理攻撃力と物理クリティカルアップのプリンパワーの\nフィールドで自分のスキルも強化し、猛攻を繰り出す。", 1, 3, 119901, 119901, 0, 1, 0, "みやこ", 450, 0, 119901, 14, 1, 0, 0, "2025/12/21 12:00:00", 1, 302);
INSERT INTO `v1_fb2df9394343aaaa378a30077f8a2452b7e4e67ba9024e68f0c7886197ee5c0a` VALUES (0, 0, "2026/03/31 11:59:59", "シズル（ノワール）", 120001, 2.375, "【物理】前衛で猛攻から味方を守護する闇のお姉ちゃん。\nバトル開始時の行動不能無効スキルで周囲の味方を守り、\n範囲を束縛するスキルで敵を牽制し、戦況を一変する。", 5, 3, 120001, 120001, 0, 1, 0, "しずる", 450, 0, 120001, 6, 5, 0, 0, "2026/03/16 10:00:00", 1, 190);
