INSERT INTO `v1_fb2df9394343aaaa378a30077f8a2452b7e4e67ba9024e68f0c7886197ee5c0a` VALUES (0, 0, "2030/12/31 15:00:00", "カズマサ", 191301, 2.22, "【物理】皆から愛される漁師町のポンコツ漁師。\nユニオンバーストは強力なスタン効果を持つが、\n自身のＨＰが50%以下では尻もちをついてしまう。\n\n・通常攻撃とユニオンバーストを駆使して戦う。", 6, 1, 191301, 191301, 0, 1, 0, "かずまさ", 450, 0, 191301, 0, 6, 0, 0, "2015/04/01 15:00:00", 1, 850);
