INSERT INTO `v1_fb2df9394343aaaa378a30077f8a2452b7e4e67ba9024e68f0c7886197ee5c0a` VALUES (0, 0, "2030/12/31 15:00:00", "主人公", 191501, 0.0, "残されたわずかな時間で宿題を終わらせんとする\nルーセント学院の生徒。楽しい夏休みの思い出を\n守るため、山積みの宿題へと立ち向かう。", 0, 0, 191501, 100101, 0, 0, 0, "しゅじんこう", 150, 0, 100101, 0, 0, 0, 0, "2015/04/01 15:00:00", 0, 1600);
